"use server";

import { prisma } from "@/lib/prisma";
import { driverSchema, DriverFormValues } from "@/lib/validations";
import { revalidatePath } from "next/cache";

export async function getDrivers() {
  try {
    const drivers = await prisma.driver.findMany({
      orderBy: { id: "desc" },
    });
    return { success: true, data: drivers };
  } catch (error) {
    console.error("Failed to fetch drivers:", error);
    return { success: false, error: "Failed to fetch drivers" };
  }
}

export async function createDriver(data: DriverFormValues) {
  try {
    const validatedData = driverSchema.parse(data);
    
    // Check for unique license
    const existing = await prisma.driver.findUnique({
      where: { licenseNumber: validatedData.licenseNumber },
    });
    
    if (existing) {
      return { success: false, error: "License number already exists" };
    }

    const driver = await prisma.driver.create({
      data: validatedData,
    });
    
    revalidatePath("/drivers");
    revalidatePath("/");
    
    return { success: true, data: driver };
  } catch (error) {
    console.error("Failed to create driver:", error);
    return { success: false, error: "Failed to create driver" };
  }
}

export async function deleteDriver(id: number) {
  try {
    await prisma.driver.delete({
      where: { id },
    });
    revalidatePath("/drivers");
    revalidatePath("/");
    return { success: true };
  } catch (error) {
    return { success: false, error: "Failed to delete driver" };
  }
}
